@app.route("/login", methods=["GET", "POST"])
def login():
    error = False
    if request.method == "POST":
        username = request.form.get("username", "").strip().lower()
        password = request.form.get("password", "").strip()
        if username in USERS and USERS[username] == password:
            resp = make_response(redirect("/"))
            resp.set_cookie("agro_session", make_token(username),
                            max_age=60*60*24*30, httponly=True)
            return resp
        error = True
    return render_template_string(LOGIN_HTML, error=error)

@app.route("/logout")
def logout():
    resp = make_response(redirect("/login"))
    resp.delete_cookie("agro_session")
    return resp

@app.route("/")
def index():
    if not check_auth(request):
        return redirect("/login")
    return get_html()

@app.route("/api/me")
def api_me():
    user = get_session_user(request)
    return jsonify({"username": user or ""})

@app.route("/api/status")
def api_status():
    try:
        with get_conn() as conn:
            with conn.cursor() as cur:
                cur.execute("SELECT value FROM meta WHERE key='last_update'")
                row = cur.fetchone()
                last_update = row[0] if row else None
                cur.execute("SELECT COUNT(*) FROM items")
                count = cur.fetchone()[0]
        return jsonify({
            "status":      "done",
            "progress":    100,
            "message":     "Datos disponibles",
            "last_update": last_update,
            "has_data":    count > 0,
            "cloud_mode":  True,
        })
    except Exception as e:
        return jsonify({"status": "error", "message": str(e), "cloud_mode": True})

@app.route("/api/data")
def api_data():
    if not check_auth(request):
        return jsonify({}), 401
    try:
        with get_conn() as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute("SELECT data FROM items ORDER BY title")
                rows = cur.fetchall()
                cur.execute("SELECT value FROM meta WHERE key='last_update'")
                meta = cur.fetchone()
                last = meta["value"] if meta else None
        items = []
        for row in rows:
            d = row["data"]
            if isinstance(d, str):
                d = json.loads(d)
            # FILTRO PILAR: solo Clásicas (gold_special) sin cuotas
            if d.get("listing_type_id") != "gold_special":
                continue
            if any(t.get("id") == "INSTALLMENTS_CAMPAIGN"
                   for t in d.get("sale_terms", [])):
                continue
            items.append(d)
        return jsonify({"items": items, "last_update": last})
    except Exception as e:
        return jsonify({"error": str(e), "trace": traceback.format_exc()}), 500

@app.route("/api/item/<item_id>")
def api_item(item_id):
    if not check_auth(request):
        return jsonify({}), 401
    try:
        with get_conn() as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute("SELECT data FROM items WHERE id=%s", (item_id,))
                row = cur.fetchone()
        if row:
            d = row["data"]
            if isinstance(d, str):
                d = json.loads(d)
            return jsonify(d)
    except Exception as e:
        return jsonify({"error": str(e)}), 500
    return jsonify({})

@app.route("/api/update", methods=["POST"])
def api_update():
    if not check_auth(request):
        return jsonify({"ok": False, "msg": "No autorizado"}), 401
    return jsonify({"ok": False, "msg": "En modo cloud — actualiza desde tu PC"})

@app.route("/api/review/<item_id>", methods=["POST"])
def api_review(item_id):
    username = get_session_user(request)
    if not username:
        return jsonify({"ok": False}), 401
    fecha = datetime.now().strftime("%d/%m/%Y %H:%M")
    try:
        with get_conn() as conn:
            with conn.cursor() as cur:
                cur.execute("""
                    INSERT INTO reviews (item_id, usuario, fecha)
                    VALUES (%s, %s, %s)
                    ON CONFLICT (item_id) DO UPDATE
                    SET usuario=EXCLUDED.usuario, fecha=EXCLUDED.fecha, ts=NOW()
                """, (item_id, username, fecha))
            conn.commit()
        return jsonify({"ok": True, "review": {"usuario": username, "fecha": fecha}})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500

@app.route("/api/reviews")
def api_reviews():
    if not check_auth(request):
        return jsonify({}), 401
    try:
        with get_conn() as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute("SELECT item_id, usuario, fecha FROM reviews")
                rows = cur.fetchall()
        return jsonify({r["item_id"]: {"usuario": r["usuario"], "fecha": r["fecha"]} for r in rows})
    except Exception:
        return jsonify({})

@app.route("/api/pause", methods=["POST"])
def api_pause():
    return jsonify({"ok": False, "msg": "No aplica en modo cloud"})

@app.route("/upload", methods=["POST"])
def upload_data():
    """Endpoint llamado por agrocentral_uploader.py"""
    auth = request.headers.get("X-Upload-Key", "")
    upload_key = os.environ.get("UPLOAD_KEY", "agrocentral_upload_2026")
    if auth != upload_key:
        return jsonify({"ok": False, "msg": "No autorizado"}), 401
    try:
        payload     = request.get_json()
        items       = payload.get("items", [])
        last_update = payload.get("last_update", datetime.now().isoformat())
        with get_conn() as conn:
            with conn.cursor() as cur:
                # Borrar todos los items viejos antes de subir los nuevos
                cur.execute("DELETE FROM items")
                for it in items:
                    cur.execute("""
                        INSERT INTO items (id, sku, title, data)
                        VALUES (%s, %s, %s, %s)
                        ON CONFLICT (id) DO UPDATE
                        SET sku=EXCLUDED.sku, title=EXCLUDED.title,
                            data=EXCLUDED.data, updated_at=NOW()
                    """, (it.get("id",""), it.get("sku",""), it.get("title",""),
                          json.dumps(it, ensure_ascii=False)))
                cur.execute("""
                    INSERT INTO meta (key, value) VALUES ('last_update', %s)
                    ON CONFLICT (key) DO UPDATE SET value=EXCLUDED.value
                """, (last_update,))
            conn.commit()
        return jsonify({"ok": True, "uploaded": len(items)})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e), "trace": traceback.format_exc()}), 500

if __name__ == "__main__":
    app.run(debug=False, port=int(os.environ.get("PORT", 8080)), host="0.0.0.0")
